        { "Description", "\240\159\147\157 \"Bow\'s arrows had a hard time landing & we wanted charged arrows to feel more impactful\"" },
        { "Description", "\240\159\146\170 Critical hit multiplier increased from 1.67x \226\134\146 2.0x" },
        { "Description", "\240\159\146\170 Projectile hitbox size increased from 2studs \226\134\146 3studs" },
        { "Description", "\240\159\148\187 Charge time increased from 1.8s \226\134\146 2.3s" },
        { "Header", "" },
        { "Header", "" },
        {
            "ContentSummary",
            "Left",
            { "Grenade Launcher" }
        },
        { "Description", "\240\159\147\157 \"The Grenade Launcher has found a hard time being used for anything other than movement\"" },
        { "Description", "\240\159\146\170 Damage increased from 40 \226\134\146 50" },
        { "Description", "\240\159\146\170 Max Ammo Reserve increased from 18 \226\134\146 24" },
        { "Header", "" },
        { "Header", "" },
        {
            "ContentSummary",
            "Left",
            { "RPG" }
        },
        { "Description", "\240\159\147\157 \"The RPG should punish players harder for not being able to dodge it\'s slow rockets\"" },
        { "Description", "\240\159\146\170 Damage increased from 50 \226\134\146 60" },
        { "Header", "" },
        { "Header", "" },
        {
            "ContentSummary",
            "Left",
            { "Sniper" }
        },
        { "Description", "\240\159\147\157 \"The Sniper should feel weak in close-quarters-combat\"" },
        { "Description", "\240\159\148\187 Move Speed decreased from -15% \226\134\146 -20%" },
        { "Header", "" },
        { "Header", "" },
        {
            "ContentSummary",
            "Left",
            { "Daggers" }
        },
        { "Description", "\240\159\147\157 \"The projectiles were difficult to land\"" },
        { "Description", "\240\159\146\170 Projectile hitbox size increased from 2studs \226\134\146 3studs" },
        { "Header", "" },
        { "Header", "" },
        {
