        { "Description", "\240\159\147\157 \"Fine-tuning Handgun\'s last balance changes\"" },
        { "Description", "\240\159\146\170 Max Ammo increased from 10 \226\134\146 12" },
        { "Description", "\240\159\148\187 Max Ammo Reserve decreased from 90 \226\134\146 84" },
        { "Header", "" },
