        { "Description", "\240\159\147\157 \"The Uzi was overbuffed in the last balance changes\"" },
        { "Description", "\240\159\148\187 Shoot spread increased from 3\194\176 \226\134\146 4\194\176" },
        { "Description", "\240\159\148\187 ADS Shoot spread increased from 0\194\176 \226\134\146 2\194\176" },
        { "Description", "\240\159\148\187 Max Ammo decreased from 30 \226\134\146 27" },
        { "Description", "\240\159\148\187 Max Ammo Reserve decreased from 120 \226\134\146 108" },
        { "Header", "" },
