        { "Title", "\240\159\144\155 BUG FIXES" },
        { "Description", "Fixed a bug that caused players to look like they aren\'t holding any weapons" },
        { "Description", "Fixed a bug where simple emotes would temporarily mute the game\'s music" },
        { "Description", "Fixed an audio bug with the Superhero, Witch Waltz, Flex, Warpmaker, & Portal Glitch emotes" },
        { "Description", "Fixed the end game win screen for Big Onyx & Legacy Onyx" },
        { "Description", "Fixed a bug where the Blip finisher would cause health & ammo drops to not spawn where the player originally died" },
        { "Description", "Fixed a visual bug where many weapons displayed a 0 Splash Radius metric in the weapons page" },
        { "Description", "Fixed a bug with Revolver where shooting normally would become disabled if you picked up an ammo drop while using the ability" },
        { "Description", "Fixed a bug where Satchels attached to surfaces that disappear, such as Trowel walls, would fall through surfaces and not re-attach to anything" },
        { "Description", "Fixed a visual bug with the Rainbow Barf finisher" },
        { "Description", "Fixed an issue with Auto Shoot where quick attacking and switching back would cause your original weapon to attack for no reason" },
        { "Description", "Fixed a bug where players could still use their weapons when a duel ended in Arcade Servers by respawning at just the right moment" },
        { "Description", "Fixed an extremely rare bug that caused flashbang blinds to be permanent" },
        { "Description", "Fixed a bug that allowed players to complete their Freeze Ray contracts by freezing windows and other non-player entities" },
        { "Description", "Fixed a bug that causes hotbar slots to visually duplicate" },
        { "Description", "Potentially fixed a rare bug where inspecting cosmetics in the Weapons page doesn\'t do anything" },
        { "Description", "Fixed a bug where throwables such as Grenade, Flashbang, etc. would have their cooldowns used up if you get frozen while throwing them" },
        { "Description", "Fixed a bug where players were able to shoot through Jump Pads" },
        { "Description", "Fixed a bug where the game would randomly change who you\'re spectating" },
        { "Description", "Fixed a visual bug with editing queue pads in a Private Server" },
        { "Description", "Fixed a rare bug that left you searching for a duel forever if a duel was found but the teleport failed" },
        { "Description", "Fixed a bug where the Riot Shield no longer worked if you emoted and waited for it to naturally finish playing" },
        { "Description", "Fixed a visual bug with the Laptop skin for the Medkit" },
        { "Description", "Fixed a bug where players could attack during an Arcade Server\'s intermission countdown" },
        { "Description", "Fixed a bug where players could \"rubberband teleport\" with a Riot Shield and Satchel in third person mode" },
        { "Description", "Fixed a bug where using the War Horn right after you quick melee would trigger the cooldown but not give any speed boost" },
        { "Description", "Fixed a speed glitch with upside down Jump Pads" },
        { "Description", "Fixed a few visual bugs on mobile devices when emoting with certain weapons" },
        { "Description", "Fixed a bug where the Broom Ride finisher could move the cube in the Dimension map" },
        { "Description", "Fixed a bug where in-game chat bubbles wouldn\'t auto-translate" },
        { "Description", "Fixed a visual bug with the Violin Crossbow skin where the neck was sticking out the body." },
        { "Description", "Fixed some collisions bugs in the Bridge map where some parts of the map blocked your bullets" },
        { "Description", "Fixed some spots in the Crossroads map where you could glitch out using the warper" },
        { "Description", "Fixed spawns in the Big Graveyard, Station, Docks, and Big Arena maps" },
        { "Description", "Fixed a lighting bug with the Graveyard maps" },
        { "Description", "Fixed a bug that caused random server restarts" },
        { "Description", "Fixed a bug where the Desert Eagle skin had a different reload speed than other Revolver skins" },
        { "Description", "Fixed various warping bugs in Crossroads, Docks, Battlegrounds, Arena, & Big Arena" },
        { "Description", "Fixed various bugs with the Snow Shovel skin, the Glorious Handgun skin, the Repulsor skin, the Hand Gun skin, the Plasma Distortion skin, the Warpeye skin, & the Camera skin" },
        { "Description", "Fixed a visual bug that made your Fists invisible when wrapped in the Weapons page" },
        { "Description", "Fixed a bug that allowed you to eliminate players in the lobby with projectile weapons in Arcade Servers" },
        { "Description", "Fixed a bug where streak tasks wouldn\'t recover properly" },
        { "Description", "Fixed a bug that allowed players to not lose their streak from ragequitting if they reached their max duel pad wins for the day first" },
        { "Description", "Fixed a bug that allowed players to quick melee through walls after dashing with Gunblade" },
        { "Description", "Fixed a bug that allowed the Riot Shield to work while emoting" },
        { "Description", "Fixed a bug where turning PVP in the Shooting Range on/off in a Private Server wouldn\'t take effect for players that are already in the Shooting Range" },
        { "Description", "Fixed a visual bug for the scores UI in FFA" },
        { "Description", "Fixed a visual bug with the health bar when switching who you\'re spectating" },
        { "Description", "Fixed a visual bug when using freecam in the Weapons page in a Private Server" },
